// Parse Vapi end-of-call report
// Supports BOTH new UUID-based Structured Outputs AND old flat format
const items = $input.all();
const body = items[0].json.body || items[0].json;
const message = body.message || body;
const call = message.call || {};
const analysis = message.analysis || {};
const rawStructuredData = analysis.structuredData || {};
const summary = analysis.summary || '';

// Parse structured data (new UUID format + old flat format)
const parsed = {};
for (const key of Object.keys(rawStructuredData)) {
  const val = rawStructuredData[key];
  if (val && typeof val === 'object' && val.name !== undefined && val.result !== undefined) {
    parsed[val.name] = val.result;
  } else {
    parsed[key] = val;
  }
}

// Call duration
const startedAt = call.startedAt ? new Date(call.startedAt) : null;
const endedAt = call.endedAt ? new Date(call.endedAt) : null;
let durationStr = '';
if (startedAt && endedAt) {
  const ms = endedAt - startedAt;
  durationStr = Math.floor(ms / 60000) + ':' + String(Math.floor((ms % 60000) / 1000)).padStart(2, '0');
}

// Date/time Berlin
const now = new Date();
const dateStr = now.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin' });
const timeStr = now.toLocaleTimeString('de-DE', { timeZone: 'Europe/Berlin', hour: '2-digit', minute: '2-digit' });

// Extract fields
const callerName = parsed.callerName || '';
const topicCategory = parsed.topicCategory || '';
const urgencyLevel = parsed.urgencyLevel || 'niski';
const followUpNeeded = parsed.followUpNeeded === true || parsed.followUpNeeded === 'true';
const callSummary = parsed['Call Summary'] || summary;
const phoneNumber = (call.customer ? call.customer.number : '') || '';

return [{
  json: {
    'Data': dateStr,
    'Godzina': timeStr,
    'Imie': callerName || 'Nieznany',
    'Telefon': phoneNumber,
    'Kategoria': topicCategory,
    'Pilnosc': urgencyLevel,
    'Podsumowanie': callSummary,
    'Rozwiazane': followUpNeeded ? 'Nie' : 'Tak',
    'Czas rozmowy': durationStr,
    'Follow-up': followUpNeeded ? 'Tak' : 'Nie'
  }
}];

const item = $input.all()[0].json;

const urgency = item.Pilnosc || 'unbekannt';
const urgencyEmoji = urgency === 'wysoki' ? '🔴' : urgency === 'sredni' ? '🟡' : '🟢';

const subject = urgencyEmoji + ' PMK Anruf: ' + (item.Kategoria || 'Neuer Anruf') + ' - ' + urgency;

const body = '<h2>' + urgencyEmoji + ' Wichtiger Anruf bei PMK Berlin</h2>' +
  '<table style="border-collapse:collapse;width:100%;max-width:600px;">' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Datum</td><td style="padding:8px;border:1px solid #ddd;">' + item.Data + ' um ' + item.Godzina + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Anrufer</td><td style="padding:8px;border:1px solid #ddd;">' + item.Imie + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Telefon</td><td style="padding:8px;border:1px solid #ddd;">' + (item.Telefon || '-') + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Kategorie</td><td style="padding:8px;border:1px solid #ddd;">' + (item.Kategoria || '-') + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Dringlichkeit</td><td style="padding:8px;border:1px solid #ddd;">' + urgencyEmoji + ' ' + urgency + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Follow-up</td><td style="padding:8px;border:1px solid #ddd;">' + item['Follow-up'] + '</td></tr>' +
  '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Zusammenfassung</td><td style="padding:8px;border:1px solid #ddd;">' + (item.Podsumowanie || '-') + '</td></tr>' +
  '</table>' +
  '<br><p style="color:#666;font-size:12px;">Automatisch gesendet vom PMK Voice Agent.</p>';

return [{ json: { subject, body } }];
